function validate(spec, args) {
  if (args.length !== spec.length) {
    throw new Error(`expected ${spec.length} args, got ${args.length}`);
  }

  const parsed = [];
  for (let i = 0; i < spec.length; i++) {
    const { name, type } = spec[i];
    const value = args[i];

    if (type === 'string') {
      parsed.push(value);
    } else if (type === 'int') {
      const num = parseInt(value, 10);
      if (isNaN(num)) {
        throw new Error(`${name} must be int`);
      }
      parsed.push(num);
    } else if (type === 'positive-int') {
      const num = parseInt(value, 10);
      if (isNaN(num) || num < 1) {
        throw new Error(`${name} must be positive-int`);
      }
      parsed.push(num);
    }
  }

  return parsed;
}

module.exports = { validate };

